import React from 'react';
import './Hero.css';
import Button from 'react-bootstrap/Button';
import Image from 'react-bootstrap/Image';
import Container from 'react-bootstrap/Container';
import Row from 'react-bootstrap/Row';
import Col from 'react-bootstrap/Col';

const Hero = () => {
  return (
    <div className='hero text-center p-5'> 
      <h1>Best Collection of Products</h1>
      <p>Lorem ipsum, dolor sit amet consectetur adipisicing elit. Provident<br /> numquam consectetur ad cum debitis eum esse sunt corporis exercitationem. Laborum, <br />voluptate. Eos, adipisci. Atque  magnam accusantium saepe, ipsam iure dolorem!</p>
      <Button variant="primary" className="my-3">Shop Now</Button>
      <Image className='image' src="../Assets/hero_image.png" rounded />
      <br /><br /><br /><br /><br /><br />
      <Container>
      <Row>
        <Col><Button variant="primary" className="my-3">Men</Button></Col>
        <Col><Button variant="primary" className="my-3">Women</Button></Col>
        <Col><Button variant="primary" className="my-3">Kids</Button></Col>
      </Row>
    </Container>
    </div>
  )
}

export default Hero;
